class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        count = 0
        for mask in range(1 << n):
            digits = []
            for i in range(n):
                if (mask >> i) & 1:
                    digits.append(1)
                else:
                    digits.append(0)
            if sum(digits) == 0 or (n > 1 and digits[0] == 0):
                continue
            num = 0
            freq = [0] * 10
            for i in range(n):
                if (mask >> i) & 1:
                    num = num * 10 + 1
                    freq[1] += 1
                else:
                    num = num * 10
            if num % k == 0:
                count += 1
            for digit in range(2, 10):
                for i in range(n):
                    if (mask >> i) & 1:
                        num = num * 10 + digit
                        freq[digit] += 1
                    else:
                        num = num * 10
                    if i == n - 1 and num % k == 0:
                        count += 1
                num = 0
                for i in range(n):
                    if (mask >> i) & 1:
                        num = num * 10 + 1
                    else:
                        num = num * 10
                for d in range(2, 10):
                    freq[d] = 0
        return count

