            if self.is_k_palindromic(freq, k):
                return 1
            return 0
        count = 0
        for digit in range(10):
            if digit == 0 and len(path) == 0:
                continue
            count += self.backtrack(n - 1, k, path + [digit])
        return count

    def is_k_palindromic(self, freq, k):
        left = ''
        right = ''
        odd_count = 0
        odd_digit = -1
        for i in range(10):
            if freq[i] % 2 == 1:
                odd_count += 1
                odd_digit = i
        if odd_count > 1:
